"import { NextResponse } from 'next/server';
import fs from 'fs';
import path from 'path';

const stateFile = path.join(process.cwd(), 'gincana-state.json');

const defaultState = {
  status: 'waiting', // waiting, active, finished
  votes: { teamA: 0, teamB: 0, teamC: 0, teamD: 0 },
  message: 'O evento vai começar...'
};

function getState() {
  try {
    if (!fs.existsSync(stateFile)) {
      fs.writeFileSync(stateFile, JSON.stringify(defaultState));
      return defaultState;
    }
    return JSON.parse(fs.readFileSync(stateFile, 'utf-8'));
  } catch (e) {
    return defaultState;
  }
}

function saveState(state: any) {
  fs.writeFileSync(stateFile, JSON.stringify(state));
}

export async function GET() {
  return NextResponse.json(getState());
}

export async function POST(request: Request) {
  const body = await request.json();

  if (body.action === 'vote') {
    const state = getState();
    // Only count votes if status is active
    if (state.status === 'active' && state.votes[body.team as keyof typeof state.votes] !== undefined) {
      state.votes[body.team as keyof typeof state.votes]++;
      saveState(state);
    }
    return NextResponse.json(state);
  }

  if (body.action === 'reset') {
    saveState(defaultState);
    return NextResponse.json(defaultState);
  }

  if (body.action === 'updateStatus') {
    const state = getState();
    state.status = body.status;
    if (body.message) state.message = body.message;
    saveState(state);
    return NextResponse.json(state);
  }

  return NextResponse.json({ error: 'Invalid action' }, { status: 400 });
}"

